form:Form.form:Scripts:
		function OnLoad()
{                      
	var day=new Date();


	Ctrl("anno").SetTypedValue(day.getFullYear());
	OnChangeAnno();  
	Ctrl("chkFeriado").SetXValue(1);   

	for(i = 0;i<Ctrl("CALS").CountRow();i++)            
	{
	 	row = Ctrl("CALS").GetRow(i);
	 	if(row.GetAttr("c_tipo") == "NOLAB")
	 	 	row.SetAttr("color","1D8CD6");

	} 
	Ctrl("CAL_ENE").SyncHTML();
	Ctrl("CAL_FEB").SyncHTML();
	Ctrl("CAL_MAR").SyncHTML();
	Ctrl("CAL_ABR").SyncHTML();
	Ctrl("CAL_MAY").SyncHTML();
	Ctrl("CAL_JUN").SyncHTML();
	Ctrl("CAL_JUL").SyncHTML();
	Ctrl("CAL_AGO").SyncHTML();
	Ctrl("CAL_SEP").SyncHTML();     
	Ctrl("CAL_OCT").SyncHTML();
	Ctrl("CAL_NOV").SyncHTML();
	Ctrl("CAL_DIC").SyncHTML();  
}                                  


function OnChangeAnno()
{
	Ctrl("CAL_ENE").SetTypedValue(Ctrl("anno").TypedValue()*100+ 1);
	Ctrl("CAL_FEB").SetTypedValue(Ctrl("anno").TypedValue()*100+ 2);
	Ctrl("CAL_MAR").SetTypedValue(Ctrl("anno").TypedValue()*100+ 3);
	Ctrl("CAL_ABR").SetTypedValue(Ctrl("anno").TypedValue()*100+ 4);

	Ctrl("CAL_MAY").SetTypedValue(Ctrl("anno").TypedValue()*100+ 5);
	Ctrl("CAL_JUN").SetTypedValue(Ctrl("anno").TypedValue()*100+ 6);
	Ctrl("CAL_JUL").SetTypedValue(Ctrl("anno").TypedValue()*100+ 7);
	Ctrl("CAL_AGO").SetTypedValue(Ctrl("anno").TypedValue()*100+ 8);

	Ctrl("CAL_SEP").SetTypedValue(Ctrl("anno").TypedValue()*100+ 9);
	Ctrl("CAL_OCT").SetTypedValue(Ctrl("anno").TypedValue()*100+10);
	Ctrl("CAL_NOV").SetTypedValue(Ctrl("anno").TypedValue()*100+11);
	Ctrl("CAL_DIC").SetTypedValue(Ctrl("anno").TypedValue()*100+12);
}

function PrevYear()
{
	Ctrl("anno").SetTypedValue(Ctrl("anno").TypedValue()-1);
	OnChangeAnno();
}

function NextYear()
{
	Ctrl("anno").SetTypedValue(Ctrl("anno").TypedValue()+1);
	OnChangeAnno();
}

function OnDayClick(Obj)
{                    
	var myStr=date2str(Obj.GetClickDate());

	if (Ctrl("CALS").GetRowByAttr("f_feriado",myStr)==null)  
	{
		row = Ctrl("CALS").AddRow();
		row.SetAttr("f_feriado",myStr);
	    row.SetAttr("color",Ctrl("chkNoLaborales").GetXValue() == "1" ? "1D8CD6" :"A00000");
	    row.SetAttr("c_tipo",Ctrl("chkNoLaborales").GetXValue() == "1" ? "NOLAB" :"FER");

	}
	else
		Ctrl("CALS").DelRowByAttr("f_feriado",myStr);

	Obj.SyncHTML();
}                     

function checkearTipoDia(estadoFer,estadoNoLab)
{    
	Ctrl("chkNoLaborales").SetXValue(estadoNoLab);
	Ctrl("chkFeriado").SetXValue(estadoFer);
}

function checkearFeriado()
{
   estadoNoLab = Ctrl("chkFeriado").GetXValue() == 1 ? 0 : 1;
   estadoFer =  Ctrl("chkFeriado").GetXValue();
   checkearTipoDia(estadoFer,estadoNoLab);                 
}   

function checkearNoLab()
{
   estadoFer = Ctrl("chkNoLaborales").GetXValue() == 1 ? 0 : 1;
   estadoNoLab =  Ctrl("chkNoLaborales").GetXValue();
   checkearTipoDia(estadoFer,estadoNoLab);                 
}
